return [{ json: { 
    confirmation_message: "You can't checkout because your cart is empty. Please add some items first\\!", 
    chat_id: $items("Start")[0].json.chat_id 
}}];

const itemsFromCart = $items();
const firstItem = itemsFromCart[0].json;

let subtotal = 0;
const orderItems = itemsFromCart.map(itemNode => {
  const item = itemNode.json;
  const lineTotal = item.quantity * parseFloat(item.unit_price);
  subtotal += lineTotal;
  return {
    sku: item.sku,
    original_name: item.original_name,
    quantity: item.quantity,
    unit: item.stock,
    unit_price: item.unit_price,
    line_total: lineTotal
  };
});

// --- PROMOTION LOGIC WOULD GO HERE ---
// For now, we'll assume no discounts.
// In the future, you would call your AI Promotions tool here
// to find the best discount for this subtotal and item list.
let final_order_total = subtotal;
let discount_applied = 0;
let promo_description = null;

// A simple bill summary message
const billSummary = orderItems.map(item => {
    return `• ${item.original_name} x ${item.quantity} = ₹${item.line_total.toFixed(2)}`;
}).join('\n');

const finalMessage = `*Please confirm your final order:*\n\n${billSummary}\n\n*Total Amount: ₹${final_order_total.toFixed(2)}*\n\nReply 'pay' to proceed to payment.`;

return [{
    json: {
        order_id: firstItem.cart_id, // We will use the cart_id as the unique ID for this order
        chat_id: firstItem.user_id,
        store_id: firstItem.store_id,
        final_order_total: final_order_total,
        items_in_final_order: orderItems,
        confirmation_message: finalMessage // The message asking the user to confirm
    }
}];
